import"./hoisted.D_V_Gr1f.js";document.addEventListener("astro:page-load",()=>{const a=document.querySelectorAll(".countdown-timer");function o(){a.forEach(e=>{const n=e.getAttribute("data-date");if(!n)return;const r=new Date(n).getTime(),s=Date.now(),t=r-s;if(t<=0){e.textContent="NOW";return}const c=Math.floor(t/(1e3*60*60*24)),d=Math.floor(t%(1e3*60*60*24)/(1e3*60*60)),i=Math.floor(t%(1e3*60*60)/(1e3*60)),u=Math.floor(t%(1e3*60)/1e3);e.textContent=`${c}D ${String(d).padStart(2,"0")}:${String(i).padStart(2,"0")}:${String(u).padStart(2,"0")}`})}o(),setInterval(o,1e3)});
